mapper.select:
SELECT p.product_id, p.tenant_id, p.seller_company_id, c.company_name as seller_company_name, p.product_code, p.product_name, p.item_kind, p.processing_type, p.tax_category, p.unit_name, p.sale_status, p.supply_price, p.vat_amount, p.sale_price, p.sale_start_at, p.sale_end_at, p.display_order, p.is_new, p.is_monthly, p.is_hidden, p.stock_manage_yn, p.safety_stock_qty, p.delivery_fee, p.created_at FROM tb_product p LEFT JOIN tb_company c ON p.seller_company_id = c.company_id WHERE 1=1
AND p.tenant_id = #{tenantId}
AND p.seller_company_id = #{sellerCompanyId}
AND EXISTS ( SELECT 1 FROM tb_product_price pp WHERE pp.product_id = p.product_id AND pp.channel_id = #{channelId} AND pp.status = 'ACTIVE' )
AND (p.product_name LIKE CONCAT('%', #{searchKeyword}, '%') OR p.product_code LIKE CONCAT('%', #{searchKeyword}, '%'))
AND p.sale_status = #{saleStatus}
ORDER BY p.created_at DESC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

SELECT COUNT(*)
FROM tb_product p
WHERE 1=1

    AND p.tenant_id = #{tenantId}


    AND p.seller_company_id = #{sellerCompanyId}


    AND EXISTS (
        SELECT 1
        FROM tb_product_price pp
        WHERE pp.product_id = p.product_id
          AND pp.channel_id = #{channelId}
          AND pp.status = 'ACTIVE'
    )


    AND (p.product_name LIKE CONCAT('%', #{searchKeyword}, '%') OR p.product_code LIKE CONCAT('%', #{searchKeyword}, '%'))


    AND p.sale_status = #{saleStatus}

SELECT CAST(
    COALESCE(
        CEIL((MAX(CAST(p.product_code AS UNSIGNED)) + 1) / 100) * 100,
        #{codeBase}
    ) AS CHAR
)
FROM tb_product p
WHERE p.tenant_id = #{tenantId}
  AND p.product_code REGEXP '^[0-9]+$'
  AND CAST(p.product_code AS UNSIGNED) >= #{codeBase}
  AND CAST(p.product_code AS UNSIGNED) < #{codeBase} + 1000000

SELECT CAST(
    COALESCE(
        CEIL((MAX(p.display_order) + 1) / 100) * 100,
        #{codeBase}
    ) AS SIGNED
)
FROM tb_product p
WHERE p.tenant_id = #{tenantId}
  AND p.display_order IS NOT NULL
  AND p.display_order >= #{codeBase}
  AND p.display_order < #{codeBase} + 1000000

