mapper.select:
SELECT p.product_id, p.product_code, p.product_name, p.processing_type, p.sale_status FROM tb_product p WHERE p.tenant_id = #{tenantId} AND p.processing_type = 'PROCESS_SERVICE' AND p.sale_status IN ('ON_SALE', 'STOPPED', 'TEMP_SAVE', 'APPROVAL_WAIT')
AND p.product_id != #{productId}
ORDER BY p.processing_type ASC, p.product_name ASC

